def solve(landStartTime: Array[Long], landDuration: Array[Long], waterStartTime: Array[Long], waterDuration: Array[Long]): Long = {
    var minTime = Long.MaxValue

    for (i <- landStartTime.indices) {
        for (j <- waterStartTime.indices) {
            // Land first, then water
            val landEnd = Math.max(landStartTime(i), 0L) + landDuration(i)
            val waterStart = Math.max(landEnd, waterStartTime(j))
            val waterEnd = waterStart + waterDuration(j)
            minTime = Math.min(minTime, waterEnd)

            // Water first, then land
            val waterEndFirst = Math.max(waterStartTime(j), 0L) + waterDuration(j)
            val landStart = Math.max(waterEndFirst, landStartTime(i))
            val landEndSecond = landStart + landDuration(i)
            minTime = Math.min(minTime, landEndSecond)
        }
    }

    minTime
}
